#!/usr/bin/env python3
"""
GPU-accelerated text-generation service for qwen2.5-0.5b.

The GEN TWIN of gpu_hidden_embed.py. Offloads the SkyMesh `runGenerate` queue
from the CPU fat-stations (which can't finish long wiki-gen prompts inside the
60s gateway lease) onto the idle GTX 1080 Ti.

Matches the fat-station gen contract EXACTLY (verified against bin/fat-station.rs;
this is what protocol69-gen-agent hits against its --fat-station-url):

  POST /tokenize   {"text":"...","add_bos":false}                        -> {"tokens":[u32,...], "count":N, "add_bos":bool}
  POST /generate   {"tokens":[u32,...],"max_new_tokens":N,"temperature":0} -> {"generated_tokens":[u32,...], "num_new_tokens":N}
  POST /detokenize {"token_ids":[u32,...]}   (also accepts "tokens")      -> {"text":"..."}

Semantics (mirrors fat-station.rs handle_generate):
  - prompt tokens are used AS-IS (the agent tokenizes with add_bos:false; /generate
    does NOT prepend BOS).
  - temperature == 0  => greedy / argmax (deterministic).
  - temperature  > 0  => softmax-with-temperature multinomial sampling.
  - generated_tokens are the NEW tokens only (prompt excluded).
  - stop at EOS: token 151643 (Qwen <|endoftext|>) or 2; the terminal EOS token
    IS included in generated_tokens (matching fat-station which pushes-then-breaks).

Model: Qwen/Qwen2.5-0.5B-Instruct (HF, fp16, cuda) — SAME weights as the fleet's
qwen05-dense knot. Tokenizer = the model's HF Qwen2 BPE tokenizer.

Launch (WSL, like the embed service):
  python3 gpu_generate.py --port 8094 --host 0.0.0.0
"""
import argparse
import json
import sys
import time
from http.server import BaseHTTPRequestHandler, ThreadingHTTPServer

import torch
from transformers import AutoModelForCausalLM, AutoTokenizer

MODEL_ID = "Qwen/Qwen2.5-0.5B-Instruct"

# Qwen EOS ids. 151643 = <|endoftext|>. 2 kept for parity with fat-station's check.
EOS_IDS = (151643, 2)

# globals populated in main()
MODEL = None
TOKENIZER = None
DEVICE = None


@torch.no_grad()
def generate(prompt_tokens, max_new_tokens, temperature):
    """Greedy (temp 0) / sampled decode. Returns list[int] of NEW tokens only
    (terminal EOS included), matching the fat-station /generate contract."""
    ids = torch.tensor([prompt_tokens], dtype=torch.long, device=DEVICE)
    past = None
    cur = ids
    generated = []
    for _ in range(max_new_tokens):
        out = MODEL(cur, past_key_values=past, use_cache=True)
        past = out.past_key_values
        logits = out.logits[:, -1, :]  # [1, vocab]
        if temperature and temperature > 0.0:
            probs = torch.softmax(logits.float() / float(temperature), dim=-1)
            tok = int(torch.multinomial(probs, num_samples=1).item())
        else:
            tok = int(torch.argmax(logits, dim=-1).item())
        generated.append(tok)
        if tok in EOS_IDS:
            break
        cur = torch.tensor([[tok]], dtype=torch.long, device=DEVICE)
    return generated


class Handler(BaseHTTPRequestHandler):
    protocol_version = "HTTP/1.1"

    def log_message(self, *a):  # quiet
        pass

    def _send_json(self, code, obj):
        body = json.dumps(obj).encode("utf-8")
        self.send_response(code)
        self.send_header("Content-Type", "application/json")
        self.send_header("Content-Length", str(len(body)))
        self.end_headers()
        self.wfile.write(body)

    def _send_text(self, code, text):
        body = text.encode("utf-8")
        self.send_response(code)
        self.send_header("Content-Type", "text/plain")
        self.send_header("Content-Length", str(len(body)))
        self.end_headers()
        self.wfile.write(body)

    def _read_json(self):
        n = int(self.headers.get("Content-Length", 0))
        raw = self.rfile.read(n) if n else b""
        return json.loads(raw) if raw else {}

    def do_GET(self):
        if self.path in ("/", "/health"):
            self._send_text(200, "ok")
        else:
            self._send_text(404, "not found")

    def do_POST(self):
        try:
            if self.path == "/tokenize":
                self._handle_tokenize()
            elif self.path == "/generate":
                self._handle_generate()
            elif self.path == "/detokenize":
                self._handle_detokenize()
            else:
                self._send_text(404, "not found")
        except Exception as e:  # noqa
            import traceback
            traceback.print_exc()
            self._send_text(500, str(e))

    def _handle_tokenize(self):
        req = self._read_json()
        text = req.get("text", "")
        add_bos = bool(req.get("add_bos", False))
        # Qwen2 has no BOS in its chat flow; encode without special tokens to match
        # the fat-station's add_bos:false semantics (the agent always sends false).
        ids = TOKENIZER.encode(text, add_special_tokens=False)
        if add_bos and TOKENIZER.bos_token_id is not None:
            ids = [TOKENIZER.bos_token_id] + ids
        self._send_json(200, {"tokens": ids, "count": len(ids), "add_bos": add_bos})

    def _handle_generate(self):
        req = self._read_json()
        tokens = [int(t) for t in req.get("tokens", [])]
        if not tokens:
            self._send_text(400, "tokens must be non-empty")
            return
        max_new = int(req.get("max_new_tokens", 1))
        temperature = float(req.get("temperature", 0.0))
        if temperature < 0.0:
            temperature = 0.0
        t = time.time()
        gen = generate(tokens, max_new, temperature)
        dt = time.time() - t
        self._send_json(200, {
            "generated_tokens": gen,
            "num_new_tokens": len(gen),
            "elapsed_ms": int(dt * 1000),
        })
        tps = (len(gen) / dt) if dt > 0 else 0.0
        sys.stderr.write(
            "generate prompt=%d new=%d temp=%g %.3fs (%.1f tok/s)\n"
            % (len(tokens), len(gen), temperature, dt, tps)
        )

    def _handle_detokenize(self):
        req = self._read_json()
        ids = req.get("token_ids")
        if ids is None:
            ids = req.get("tokens")  # symmetry with /tokenize response field
        if ids is None:
            self._send_text(400, "missing field: token_ids (array of u32)")
            return
        ids = [int(t) for t in ids]
        text = TOKENIZER.decode(ids, skip_special_tokens=False)
        self._send_json(200, {"text": text})


def main():
    global MODEL, TOKENIZER, DEVICE
    ap = argparse.ArgumentParser()
    ap.add_argument("--port", type=int, default=8094)
    ap.add_argument("--host", default="0.0.0.0")
    ap.add_argument("--model", default=MODEL_ID)
    args = ap.parse_args()

    if not torch.cuda.is_available():
        sys.stderr.write("FATAL: CUDA not available\n")
        sys.exit(1)
    DEVICE = "cuda"
    sys.stderr.write("loading %s onto %s (fp16)...\n" % (args.model, DEVICE))
    TOKENIZER = AutoTokenizer.from_pretrained(args.model)
    MODEL = AutoModelForCausalLM.from_pretrained(
        args.model, torch_dtype=torch.float16
    ).to(DEVICE).eval()
    sys.stderr.write(
        "loaded. gpu_mem_alloc=%.2fGB hidden=%d eos=%s\n"
        % (torch.cuda.memory_allocated() / 1e9, MODEL.config.hidden_size, EOS_IDS)
    )
    # warmup: prefill + a couple decode steps to trigger CUDA kernel compile.
    _ = generate([785, 6722, 315], 2, 0.0)
    sys.stderr.write("warmup done\n")

    srv = ThreadingHTTPServer((args.host, args.port), Handler)
    sys.stderr.write(
        "serving /tokenize /generate /detokenize on %s:%d\n" % (args.host, args.port)
    )
    srv.serve_forever()


if __name__ == "__main__":
    main()
